     public function BuildComputedResult()
        {
                // Put your code here, call parent::CalculatePowerData(...); if needed
                IssueLog::Debug("BuildComputedResult: Name: ".$this->Get('name'), 'Delta XML');

				$sOql = trim((string)$this->Get('oql_query'));
				$sGroupBy = trim((string)$this->Get('group_by_attcode'));

				if ($sOql === '') {
					throw new Exception(Dict::S('Class:OQLGroupByIndicator/Error:EmptyOQL'));
					return;
				}

				if ($sGroupBy === '') {
					throw new Exception(Dict::S('Class:OQLGroupByIndicator/Error:EmptyGroupBy'));
					return;
				}

				$oSearch = DBObjectSearch::FromOQL($sOql);
				$oSet = new DBObjectSet($oSearch);

				$aRows = array();

				while ($oObj = $oSet->Fetch()) {
					if(is_null($oObj)) {
						continue;
					}
					$sClass = get_class($oObj);
					if (!MetaModel::IsValidAttCode($sClass, $sGroupBy)) {
						throw new Exception(sprintf(Dict::S('Class:OQLGroupByIndicator/Error:InvalidAttribute'), $sGroupBy, $sClass));
					}

					$mRawValue = $oObj->Get($sGroupBy);
					$sRawKey = is_scalar($mRawValue) ? (string)$mRawValue : serialize($mRawValue);
					$sHtmlValue = $oObj->GetAsHTML($sGroupBy);

					if (($mRawValue === '') || ($mRawValue === null)) {
						$sRawKey = '__empty__';
						$sHtmlValue = $this->EscapeHtml($this->Get('empty_value_label'));
					}

					if (!isset($aRows[$sRawKey])) {
						$aRows[$sRawKey] = array(
							'raw_value' => $mRawValue,
							'label' => $sHtmlValue,
							'count' => 0,
						);
					}

					$aRows[$sRawKey]['count']++;
				}

				//$this->SortRows($aRows, $this->Get('sort_mode'));
				$aData=array_shift($aRows);

				return $aData['count'];
        }

public function EvtSetAttributesFlagsResult(Combodo\iTop\Service\Events\EventData $oEventData)
   {

           // The target state in which to evaluate the flags
           // $oEventData->Get('target_state') returns an array
           $this->AddAttributeFlags('result', OPT_ATT_READONLY);

   }

     public function EvtRefreshOQLGroupByIndicators(Combodo\iTop\Service\Events\EventData $oEventData)
        {

                // Creation flag
                // $oEventData->Get('is_new') returns a boolean

                // For updates, the list of changes done during this operation
                // $oEventData->Get('changes') returns an array

				$sFinalClass = $this->Get('finalclass');

				if ($sFinalClass === '') {
					$sFinalClass = get_class($this);
				}

				$oSearch = DBObjectSearch::FromOQL('SELECT OQLGroupByIndicator WHERE oql_query LIKE \'SELECT '.$sFinalClass.' %\' OR \'SELECT FunctionalCI %\'');
				$oSet = new DBObjectSet($oSearch);

				while ($oIndicator = $oSet->Fetch()) {
					$newResult=$oIndicator->BuildComputedResult();
					$oIndicator->Set("result",$newResult);
					$oIndicator->DBUpdate();
				}
        }

